# ── Reusable context manager guaranteeing db.close() on exit ──────────────────
@contextmanager
def db_session():
    """Context manager for get_db() that guarantees cleanup."""
    db = get_db()
    try:
        yield db
    finally:
        try:
            db.close()
        except Exception:
            pass


def _load_api_keys_from_db():
    try:
        from engines.ruflo_20phase_engine import Cfg
        db = get_db()
        _ensure_settings_table(db)
        rows = db.execute("SELECT key, value_enc FROM api_settings").fetchall()
        for r in rows:
            key = r["key"]
            value_enc = r["value_enc"] or ""
            val = _decrypt(value_enc)
            if not val and value_enc:
                # Legacy fallback: if plain text API key was stored without encryption, keep it.
                if value_enc.startswith("gsk_") or value_enc.startswith("sk-"):
                    val = value_enc
                    log.info(f"[Settings] Loaded plaintext API key for {key} as fallback")
            if not val:
                continue
            val = val.strip()
            mapping = {
                "groq_key":           "GROQ_API_KEY",
                "gemini_key":         "GEMINI_API_KEY",
                "gemini_paid_key":    "GEMINI_PAID_API_KEY",
                "anthropic_key":      "ANTHROPIC_API_KEY",
                "anthropic_paid_key": "ANTHROPIC_PAID_API_KEY",
                "openai_key":         "OPENAI_API_KEY",
                "openai_paid_key":    "OPENAI_PAID_API_KEY",
                "ollama_url":         "OLLAMA_URL",
                "ollama_model":       "OLLAMA_MODEL",
                "groq_model":         "GROQ_MODEL",
            }
            env_key = mapping.get(key)
            if env_key:
                os.environ[env_key] = val
        Cfg.refresh_from_env()
        # Sync all provider key pools into {PROVIDER}_ALL_KEYS env vars
        _sync_provider_all_keys()
    except Exception as e:
        log.warning(f"[Settings] Could not load API keys from DB: {e}")

@app.on_event("startup")
async def startup():
    # If running tests, avoid starting background services and heavy engine init
    if os.getenv("ANNASEO_TESTING", "").lower() in ("1", "true", "yes"):
        try:
            get_db()
        except Exception:
            pass
        try:
            get_logger("annaseo.main").info("[AnnaSEO] TEST MODE: skipping background services and engines")
        except Exception:
            pass
        return

    try:
        get_db()
        _ensure_ollama_servers_table(get_db())
        setup_sentry()
        setup_opentelemetry(app)
        _load_api_keys_from_db()
        _mount_engines()

        # Initialize SQLAlchemy tables for error logging
        try:
            init_error_db()
            get_logger("annaseo.main").info("[AnnaSEO] Error DB init ready")
        except Exception as e:
            get_logger("annaseo.main").warning(f"Error DB init failed: {e}")

        # Initialize kw2 tables
        try:
            init_kw2_db()
            get_logger("annaseo.main").info("[AnnaSEO] kw2 DB init ready")
        except Exception as e:
            get_logger("annaseo.main").warning(f"kw2 DB init failed: {e}")

        # Seed kw2 prompt registry
        try:
            from engines.kw2.prompt_manager import PromptManager as _KW2PromptManager
            _KW2PromptManager().seed_all()
            get_logger("annaseo.main").info("[AnnaSEO] kw2 prompt registry seeded")
        except Exception as e:
            get_logger("annaseo.main").warning(f"kw2 prompt seed failed: {e}")

        # Start alert checker loop
        def _alert_loop():
            while True:
                try:
                    check_alerts()
                except Exception as e:
                    log.warning("alert_loop_error", error=str(e))
                time.sleep(int(os.getenv("ALERT_CHECK_INTERVAL", "60")))

        t = threading.Thread(target=_alert_loop, daemon=True)
        t.start()

        # Auto-cleanup: expire old SERP cache entries (>30 days)
        try:
            with db_session() as _cdb:
                _cdb.execute(
                    "DELETE FROM serp_cache WHERE fetched_at < datetime('now', '-30 days')"
                )
                _cdb.commit()
                get_logger("annaseo.main").info("[AnnaSEO] SERP cache GC: expired old entries")
        except Exception:
            pass

        # Recover articles stuck in 'generating' from a previous crash/kill
        try:
            with db_session() as _cdb:
                # Ensure error_message column exists (migration for existing DBs)
                try:
                    _cdb.execute("ALTER TABLE content_articles ADD COLUMN error_message TEXT DEFAULT ''")
                    _cdb.commit()
                except Exception:
                    pass  # column already exists
                cur = _cdb.execute(
                    "SELECT article_id FROM content_articles WHERE status='generating'"
                )
                stuck = [r[0] for r in cur.fetchall()]
                if stuck:
                    _cdb.execute(
                        "UPDATE content_articles SET status='failed', "
                        "error_message='Service restarted while article was generating — click Retry to resume' "
                        "WHERE status='generating'"
                    )
                    _cdb.commit()
                    get_logger("annaseo.main").warning(
                        f"[AnnaSEO] Recovered {len(stuck)} stuck article(s) → failed: {stuck}"
                    )
        except Exception as _e:
            get_logger("annaseo.main").warning(f"[AnnaSEO] Stuck-article recovery error: {_e}")

        # Load disabled providers from DB
        try:
            from engines.content_generation_engine import _set_provider_disabled
            with db_session() as _cdb:
                _dp_row = _cdb.execute(
                    "SELECT value_enc FROM api_settings WHERE key='disabled_providers'"
                ).fetchone()
            if _dp_row and _dp_row[0]:
                _disabled_list = json.loads(_decrypt(_dp_row[0]))
                for _dp in _disabled_list:
                    _set_provider_disabled(_dp, True)
                get_logger("annaseo.main").info(
                    f"[AnnaSEO] Loaded {len(_disabled_list)} disabled provider(s): {_disabled_list}"
                )
        except Exception as _e:
            get_logger("annaseo.main").warning(f"[AnnaSEO] Disabled providers load error: {_e}")

        get_logger("annaseo.main").info("[AnnaSEO] Ready")
    except Exception as e:
        get_logger("annaseo.main").error(f"Startup failed but continuing with limited operations: {e}")


@app.on_event("shutdown")
def shutdown():
    get_logger("annaseo.main").info("[AnnaSEO] Shutting down gracefully")
    # worker and other services should use signal-based stop controls

# ── Auth ─────────────────────────────────────────────────────────────────────
def _load_jwt_secret():
    """Load or generate a persistent JWT secret."""
    env_val = os.getenv("JWT_SECRET")
    if env_val:
        return env_val
    secret_file = Path(__file__).resolve().parent / ".jwt_secret"
    if secret_file.exists():
        return secret_file.read_text().strip()
    new_secret = secrets.token_hex(32)
    secret_file.write_text(new_secret)
    secret_file.chmod(0o600)
    return new_secret

JWT_SECRET    = _load_jwt_secret()
oauth2_scheme = OAuth2PasswordBearer(tokenUrl="/api/auth/login")

def _hash_pw(pw): return sha256(f"{pw}{JWT_SECRET}".encode()).hexdigest()

def _make_token(uid, email, role, ttl=43200):  # 30 days
    import base64
    exp = (datetime.utcnow()+timedelta(minutes=ttl)).isoformat()
    p   = json.dumps({"user_id":uid,"email":email,"role":role,"exp":exp})
    sig = hmac.new(JWT_SECRET.encode(),p.encode(),sha256).hexdigest()
    return f"{base64.urlsafe_b64encode(p.encode()).decode()}.{sig}"

def _verify_token(token):
    import base64
    try:
        d,sig = token.rsplit(".",1)
        p     = base64.urlsafe_b64decode(d.encode()).decode()
        if not hmac.compare_digest(sig, hmac.new(JWT_SECRET.encode(),p.encode(),sha256).hexdigest()): return None
        data  = json.loads(p)
        if datetime.fromisoformat(data["exp"]) < datetime.utcnow(): return None
        return data
    except: return None

async def current_user(token: str=Depends(oauth2_scheme)):
    data = _verify_token(token)
    if not data: raise HTTPException(401,"Invalid or expired token")
    return data

async def current_user_or_qs(request: Request, token: str = None):
    """Auth via Bearer header or ?token= query param (for SSE EventSource)."""
    # Try query param first (SSE can't set headers)
    if token:
        data = _verify_token(token)
        if data: return data
    # Fallback to header
    auth = request.headers.get("authorization", "")
    if auth.startswith("Bearer "):
        data = _verify_token(auth[7:])
        if data: return data
    raise HTTPException(401, "Invalid or expired token")

class RegisterBody(BaseModel):
    email: str; name: str; password: str

@app.post("/api/auth/register",tags=["Auth"])
def register(body: RegisterBody):
    db=get_db(); uid=f"user_{hashlib.md5(body.email.encode()).hexdigest()[:10]}"
    if db.execute("SELECT 1 FROM users WHERE email=?",(body.email,)).fetchone(): raise HTTPException(400,"Already registered")
    db.execute("INSERT INTO users(user_id,email,name,pw_hash)VALUES(?,?,?,?)",(uid,body.email,body.name,_hash_pw(body.password))); db.commit()
    return {"access_token":_make_token(uid,body.email,"user"),"user_id":uid}

@app.post("/api/auth/login",tags=["Auth"])
def login(form: OAuth2PasswordRequestForm=Depends()):
    db=get_db(); user=db.execute("SELECT * FROM users WHERE email=?",(form.username,)).fetchone()
    if not user or dict(user)["pw_hash"]!=_hash_pw(form.password): raise HTTPException(401,"Invalid credentials")
    u=dict(user)
    return {"access_token":_make_token(u["user_id"],u["email"],u["role"]),"user_id":u["user_id"],"email":u["email"],"role":u["role"]}

@app.post("/api/auth/stream-token", tags=["Auth"])
def stream_token(user=Depends(current_user)):
    """Issue a short-lived token (2 min) for SSE streams so the long-lived
    JWT is never placed in a URL query string (B29)."""
    return {"stream_token": _make_token(user["user_id"], user["email"], user.get("role", "user"), ttl=2)}

@app.get("/api/auth/me",tags=["Auth"])
def me(user=Depends(current_user)):
    row=get_db().execute("SELECT user_id,email,name,role FROM users WHERE user_id=?",(user["user_id"],)).fetchone()
    if not row: raise HTTPException(404,"Not found")
    return dict(row)

