# Stagger concurrent pipeline starts to avoid simultaneous Groq rate limits
_pipeline_start_counter = 0
_pipeline_start_lock = asyncio.Lock()

# Track active pipelines for pause/resume/rerun
_active_pipelines: Dict[str, "SEOContentPipeline"] = {}

async def _gen_article(article_id, body, step_mode: str = "auto", start_step: int = 1):
    """Run the real 10-step SEO content pipeline for an article."""
    global _pipeline_start_counter
    db = get_db()
    try:
        # ── Memory gate: wait if system memory is over 80% ───────────────
        for _wait_attempt in range(10):  # max ~100s wait
            try:
                with open("/proc/meminfo") as _f:
                    _info = {}
                    for _line in _f:
                        _parts = _line.split()
                        if len(_parts) >= 2:
                            _info[_parts[0].rstrip(":")] = int(_parts[1])
                    _mem_pct = (1 - _info.get("MemAvailable", _info.get("MemTotal", 1)) / _info.get("MemTotal", 1)) * 100
            except Exception:
                _mem_pct = 0
            if _mem_pct < 80:
                break
            log.warning(f"Memory at {_mem_pct:.0f}% — delaying pipeline start for {article_id} (attempt {_wait_attempt+1})")
            await asyncio.sleep(10)

        # Stagger starts: each concurrent article waits an extra N seconds so
        # they don't all hit Groq's rate limit simultaneously
        async with _pipeline_start_lock:
            stagger = _pipeline_start_counter * 5   # 0s, 5s, 10s, 15s...
            _pipeline_start_counter += 1

        if stagger > 0:
            log.info(f"Staggering pipeline start by {stagger}s for {article_id}")
            await asyncio.sleep(stagger)

        proj = db.execute("SELECT * FROM projects WHERE project_id=?", (body.project_id,)).fetchone()
        proj_name = dict(proj)["name"] if proj else "Business"

        from engines.content_generation_engine import SEOContentPipeline
        pipeline = SEOContentPipeline(
            article_id=article_id,
            keyword=body.keyword,
            intent=getattr(body, "intent", "informational"),
            project_name=proj_name,
            title=getattr(body, "title", "") or "",
            word_count=getattr(body, "word_count", 2000) or 2000,
            project_id=body.project_id,
            db=db,
            supporting_keywords=getattr(body, "supporting_keywords", []) or [],
            product_links=getattr(body, "product_links", []) or [],
            target_audience=getattr(body, "target_audience", "") or "",
            content_type=getattr(body, "content_type", "blog") or "blog",
            research_ai=getattr(body, "research_ai", "auto") or "auto",
            ai_routing=_build_routing(body),
            page_type=getattr(body, "page_type", "article") or "article",
            page_inputs=getattr(body, "page_inputs", {}) or {},
            pipeline_mode=getattr(body, "pipeline_mode", "standard") or "standard",
        )
        # Rerun safeguard: when restarting from step 10+ (score/quality/redevelop),
        # hydrate runtime state from the persisted article body so those steps do
        # not run against empty HTML.
        if int(start_step or 1) > 9:
            try:
                _ar = db.execute(
                    "SELECT body, title, meta_title, meta_desc, word_count FROM content_articles WHERE article_id=?",
                    (article_id,),
                ).fetchone()
                if _ar and _ar["body"]:
                    pipeline.state.draft_html = _ar["body"]
                    pipeline.state.final_html = _ar["body"]
                    pipeline.state.title = _ar["title"] or pipeline.state.title
                    pipeline.state.meta_title = _ar["meta_title"] or pipeline.state.meta_title
                    pipeline.state.meta_desc = _ar["meta_desc"] or pipeline.state.meta_desc
                    pipeline.state.word_count = int(_ar["word_count"] or pipeline.state.word_count or 0)
            except Exception as _hydrate_err:
                log.warning(f"Rerun hydrate skipped for {article_id}: {_hydrate_err}")
        # Load Ollama servers from DB so engine can resolve ollama_remote_{id}
        try:
            _ensure_ollama_servers_table(db)
            rows = db.execute("SELECT server_id, url, model FROM ollama_servers WHERE enabled=1").fetchall()
            pipeline._ollama_servers = {r["server_id"]: (r["url"], r["model"] or "") for r in rows}
        except Exception:
            pass

        # Register so pause/resume/rerun can find it
        _active_pipelines[article_id] = pipeline
        try:
            await pipeline.run(step_mode=step_mode, start_step=start_step)
        finally:
            _active_pipelines.pop(article_id, None)
    except Exception as e:
        _err_msg = str(e)[:1000]  # cap at 1000 chars
        db.execute(
            "UPDATE content_articles SET status='failed', error_message=? WHERE article_id=?",
            (_err_msg, article_id)
        )
        db.commit()
        log.error(f"_gen_article pipeline failed for {article_id}: {e}", exc_info=True)
    finally:
        async with _pipeline_start_lock:
            _pipeline_start_counter = max(0, _pipeline_start_counter - 1)


async def _publish_article(article_id,article):
    db=get_db()
    try:
        from ruflo_publisher import Publisher,ArticlePayload
        proj=db.execute("SELECT * FROM projects WHERE project_id=?",(article["project_id"],)).fetchone()
        if not proj or not dict(proj).get("wp_url"):
            db.execute("UPDATE content_articles SET status='approved',published_url='no-wp-configured' WHERE article_id=?",(article_id,)); db.commit(); return
        pub=Publisher(wp_url=dict(proj)["wp_url"],wp_user=dict(proj)["wp_user"],wp_app_password=_decrypt(dict(proj)["wp_pass_enc"]))
        res=pub.publish(ArticlePayload(article_id=article_id,title=article["title"],body=article["body"],keyword=article["keyword"],meta_title=article["meta_title"],meta_description=article["meta_desc"]))
        db.execute("UPDATE content_articles SET status='published',published_url=?,published_at=? WHERE article_id=?",(res.get("url",""),datetime.now(timezone.utc).isoformat(),article_id)); db.commit()
    except Exception as e:
        db.execute("UPDATE content_articles SET status='publish_failed' WHERE article_id=?",(article_id,)); db.commit(); log.error(f"Publish failed: {e}")

# ── Calendar ──────────────────────────────────────────────────────────────────
@app.get("/api/projects/{project_id}/calendar-items", tags=["Calendar"])
def get_calendar_items(project_id: str, month: Optional[str]=None, pillar: Optional[str]=None):
    """Return content calendar items for a project.

    Pulls from content_articles with schedule_date set, or scaffolds a 1-year
    plan from pending/draft articles if no scheduled items exist yet.
    """
    db = get_db()
    rows = db.execute(
        "SELECT article_id,keyword,title,status,frozen,schedule_date,published_at,created_at "
        "FROM content_articles WHERE project_id=? ORDER BY schedule_date,created_at",
        (project_id,)
    ).fetchall()
    items = [dict(r) for r in rows]

    # If no schedule_dates set, auto-scaffold: spread articles across next 12 months
    unscheduled = [i for i in items if not i.get("schedule_date")]
    if unscheduled:
        from datetime import date, timedelta
        start = date.today().replace(day=1)
        for idx, item in enumerate(unscheduled):
            # 2 articles per week starting from today
            sched = start + timedelta(days=idx * 3)
            item["schedule_date"] = sched.isoformat()
            item["auto_scheduled"] = True

    # Filter by month (YYYY-MM) if requested
    if month:
        items = [i for i in items if (i.get("schedule_date") or "").startswith(month)]

    # Group by month for calendar view
    monthly: dict = {}
    for item in items:
        sd = item.get("schedule_date") or item.get("created_at","")[:10]
        ym = sd[:7] if sd else "undated"
        monthly.setdefault(ym, []).append(item)

    return {
        "items": items,
        "by_month": monthly,
        "total": len(items),
        "scheduled": len([i for i in items if i.get("schedule_date")]),
        "frozen": len([i for i in items if i.get("frozen")]),
        "published": len([i for i in items if i.get("status") == "published"]),
    }

@app.put("/api/content/{article_id}/schedule", tags=["Calendar"])
def schedule_article(article_id: str, schedule_date: str, user=Depends(current_user)):
    """Set a publish schedule date for an article (YYYY-MM-DD)."""
    db = get_db()
    if not db.execute("SELECT 1 FROM content_articles WHERE article_id=?", (article_id,)).fetchone():
        raise HTTPException(404, "Not found")
    db.execute("UPDATE content_articles SET schedule_date=?,updated_at=? WHERE article_id=?",
            (schedule_date, datetime.now(timezone.utc).isoformat(), article_id))
    db.commit()
    return {"article_id": article_id, "schedule_date": schedule_date}

