    def _validate_project_exists(project_id: str, user: dict | None = None):
        db = get_db()
        # Primary check: main projects table
        row = db.execute("SELECT owner_id FROM projects WHERE project_id=?", (project_id,)).fetchone()
        if row:
            if user is not None:
                uid = user.get("user_id")
                has_link = db.execute(
                    "SELECT 1 FROM user_projects WHERE user_id=? AND project_id=?",
                    (uid, project_id),
                ).fetchone()
                is_owner = (row["owner_id"] == uid)
                if not has_link and not is_owner:
                    raise HTTPException(404, f"Project not found: {project_id}")
                if is_owner and not has_link:
                    try:
                        db.execute(
                            "INSERT OR IGNORE INTO user_projects(user_id,project_id,role)VALUES(?,?,?)",
                            (uid, project_id, "owner"),
                        )
                        db.commit()
                    except Exception:
                        pass
            return

        # Fallback: allow KI-backed projects (legacy or imported) by checking KI DB
        try:
            db2 = _ki_db()
            try:
                if db2.execute("SELECT 1 FROM keyword_input_sessions WHERE project_id=?", (project_id,)).fetchone():
                    if user is not None:
                        uid = user.get("user_id")
                        linked = db.execute(
                            "SELECT 1 FROM user_projects WHERE user_id=? AND project_id=?",
                            (uid, project_id),
                        ).fetchone()
                        if not linked:
                            raise HTTPException(404, f"Project not found: {project_id}")
                    return
            finally:
                try: db2.close()
                except Exception: pass
        except Exception:
            # If KI subsystem not available, fall through to raise
            pass

        raise HTTPException(404, f"Project not found: {project_id}")

    @app.post("/api/ki/{project_id}/input", tags=["KeywordInput"])
    def ki_save_input(project_id: str, body: _KIInput, bg: BackgroundTasks, user=Depends(current_user)):
        """Save customer pillar + supporting keywords, trigger cross-multiply, return session_id."""
        _validate_project_exists(project_id, user)
        # Normalize business_intent: accept both string and list
        bi = body.business_intent
        if isinstance(bi, list):
            bi_str = ",".join(bi) if bi else "mixed"
        else:
            bi_str = bi or "mixed"
        
        # Normalize intent_focus: accept both string and list, store as comma-separated string
        if_val = body.intent_focus
        if isinstance(if_val, list):
            if_str = ",".join(if_val) if if_val else "transactional"
        else:
            if_str = if_val or "transactional"

        # Convert pillars from List[str] to List[dict] for save_customer_input
        pillars_as_dicts = [{"keyword": p, "intent": "transactional", "priority": 1}
                           if isinstance(p, str) else p
                           for p in (body.pillars or [])]

        try:
            sid = _kie.save_customer_input(
                project_id=project_id,
                pillars=pillars_as_dicts,
                supporting=body.supporting,
                pillar_support_map=body.pillar_support_map or {},
                intent_focus=if_str,
                customer_url=body.customer_url,
                competitor_urls=body.competitor_urls,
                business_intent=bi_str,
                target_audience=body.target_audience,
                geographic_focus=body.geographic_focus,
            )

            # 💾 Save customer_url and competitor_urls to projects table for persistence
            try:
                db = get_db()
                db.execute(
                    "UPDATE projects SET customer_url=?, competitor_urls=? WHERE project_id=?",
                    (body.customer_url or "", json.dumps(body.competitor_urls or []), project_id)
                )
                db.commit()
                db.close()
            except Exception as e:
                log.warning(f"[main] Failed to persist URLs to projects table: {e}")

            # Trigger cross_multiply immediately in background so review queue has items
            bg.add_task(_kie.generate_universe, project_id=project_id, session_id=sid,
                        customer_url=body.customer_url or "",
                        competitor_urls=body.competitor_urls or [])
            return {"session_id": sid, "status": "saved", "business_intent": bi_str}

        except sqlite3.IntegrityError as e:
            log.warning(f"[main] ki_save_input integrity error for {project_id}: {e}")
            latest = _kie.get_latest_session(project_id)
            if latest:
                return {"session_id": latest.get("session_id"), "status": "duplicate"}
            raise HTTPException(409, "Duplicate session / invalid input")

        except sqlite3.OperationalError as e:
            log.error(f"[main] ki_save_input DB locked for {project_id}: {e}")
            raise HTTPException(503, "Database busy, please retry")

        except Exception as e:
            log.exception("[main] ki_save_input failed")
            raise HTTPException(500, "Failed to save input")

