    db = get_db()
    q = "SELECT * FROM ranking_alerts WHERE project_id=?"
    p: list = [project_id]
    if severity: q += " AND severity=?"; p.append(severity)
    if status:   q += " AND status=?";   p.append(status)
    q += " ORDER BY created_at DESC LIMIT 100"
    rows = db.execute(q, p).fetchall()
    result = []
    for r in rows:
        d = dict(r)
