@app.post("/api/gsc/{project_id}/tasks", tags=["GSC"])
async def gsc_tasks_create(project_id: str, body: dict, user=Depends(current_user)):
    """Create a new task. body: { task_type, title, keyword?, cluster?, description?, priority? }"""
